INSERT INTO `news_events` (`event_id`, `event_date`, `title_vi`, `title_en`, `summary_vi`, `source`, `category`, `sentiment`, `affected_lines`, `affected_ports`, `affected_regions`) VALUES
('N001', '2024-05-20', 'Maersk và Hapag-Lloyd công bố liên minh Gemini — kỷ nguyên 2M kết thúc', 'Maersk and Hapag-Lloyd announce Gemini Cooperation — 2M era ends', 'Maersk và Hapag-Lloyd công bố liên minh Gemini Cooperation có hiệu lực 2/2025. Dự kiến vận hành 290 tàu, 3.4M TEU theo mô hình hub-and-spoke, giảm port call lẻ tại cảng phụ.', 'Phaata', 'alliance', 'neutral', '["L02", "L05"]', '["P006"]', '["global"]'),
('N002', '2024-06-10', 'THE Alliance tái cấu trúc thành Premier Alliance', 'THE Alliance restructures into Premier Alliance', 'ONE, HMM, Yang Ming công bố lập Premier Alliance từ 2/2025 sau khi Hapag rời đi. Quy mô 240 tàu 1.9M TEU.', 'Alphaliner', 'alliance', 'neutral', '["L06", "L08", "L09"]', '[]', '["global"]'),
('N003', '2024-08-15', 'Ocean Alliance gia hạn hợp tác đến 2032', 'Ocean Alliance extends cooperation to 2032', 'CMA CGM, COSCO, Evergreen và OOCL gia hạn Ocean Alliance thêm 5 năm đến 2032 — lớn nhất toàn cầu ~6M TEU, 30% thị phần Asia-Europe.', 'Linerlytica', 'alliance', 'positive', '["L03", "L04", "L07", "L16"]', '["P006"]', '["global"]'),
('N004', '2024-09-05', 'MSC độc lập — kế hoạch mở rộng 5 triệu TEU', 'MSC goes independent — expands to 5M TEU', 'MSC xác nhận sẽ độc lập từ 2/2025, khai thác đội tàu 5M TEU (19.8% thị phần toàn cầu) không qua liên minh. Hãng đang tìm đối tác cảng Việt Nam.', 'Alphaliner', 'alliance', 'neutral', '["L01"]', '[]', '["global"]'),
('N005', '2024-11-12', 'Giá sàn bốc xếp sẽ tăng 10% cho cảng nước sâu từ 2/2026', 'Stevedoring price floor to rise 10% for deepsea ports from Feb 2026', 'Bộ Xây dựng đề xuất sửa đổi QĐ 810/QĐ-BGTVT, tăng 10% khung giá sàn cho cảng nước sâu áp dụng từ 1/2/2026 — hỗ trợ đầu tư cảng.', 'Cổng thông tin Bộ XD', 'regulation', 'positive', '[]', '["P006", "P014", "P015", "P021", "P022"]', '["VN"]'),
('N006', '2024-12-15', 'TCIT ký MOU với Gemini Cooperation làm hub miền Nam', 'TCIT signs MOU with Gemini as southern hub', 'Tân Cảng - Cái Mép Thị Vải (TCIT) ký Biên bản ghi nhớ với Gemini Cooperation, dự kiến là hub chính tại Việt Nam cho Maersk và Hapag-Lloyd từ 2/2025.', 'Phaata', 'route', 'negative', '["L02", "L05"]', '["P010", "P006"]', '["CM-TV"]'),
('N007', '2025-01-31', '2M Alliance chính thức giải thể', '2M Alliance officially dissolves', 'Sau 10 năm, liên minh 2M giữa Maersk và MSC chính thức giải thể. Hai hãng chọn chiến lược riêng.', 'Lloyd List', 'alliance', 'neutral', '["L01", "L02"]', '[]', '["global"]'),
('N008', '2025-02-01', 'Gemini Cooperation chính thức vận hành', 'Gemini Cooperation officially launches', 'Maersk và Hapag-Lloyd bắt đầu vận hành liên minh Gemini Cooperation theo mô hình hub-and-spoke. Các tuyến chính giảm số port call, tăng reliability.', 'Lloyd List', 'alliance', 'neutral', '["L02", "L05"]', '["P006", "P010"]', '["global"]'),
('N009', '2025-02-01', 'Premier Alliance khai trương', 'Premier Alliance starts operations', 'ONE, HMM, Yang Ming vận hành Premier Alliance từ hôm nay. 240 tàu phục vụ Asia-Europe và TransPacific.', 'Lloyd List', 'alliance', 'neutral', '["L06", "L08", "L09"]', '[]', '["global"]'),
('N010', '2025-02-01', 'Ocean Alliance bước vào chu kỳ mới', 'Ocean Alliance enters new cycle', 'CMA CGM, COSCO, Evergreen, OOCL chính thức khởi động Ocean Alliance gia hạn — cam kết đầu tư tuyến mới.', 'Alphaliner', 'alliance', 'positive', '["L03", "L04", "L07", "L16"]', '["P006"]', '["global"]'),
('N011', '2025-02-10', 'ZIM ký thoả thuận slot với MSC trên tuyến xuyên Thái Bình Dương', 'ZIM partners with MSC on TransPacific slots', 'ZIM và MSC công bố thoả thuận chia sẻ slot trên tuyến Asia-Americas. ZIM tăng hiện diện CM-TV để kết nối hub US West Coast.', 'Alphaliner', 'alliance', 'positive', '["L01", "L10"]', '["P010", "P013", "P006"]', '["CM-TV"]'),
('N012', '2025-02-18', 'Maersk xác nhận chuyển hub miền Nam Việt Nam sang TCIT', 'Maersk confirms shift of southern VN hub to TCIT', 'Trong briefing đầu tiên của Gemini tại VN, Maersk xác nhận Gemalink sẽ giảm call, TCIT thành hub chính.', 'Phaata', 'route', 'negative', '["L02"]', '["P006", "P010"]', '["CM-TV"]'),
('N013', '2025-03-05', 'Gemalink công suất mới: giai đoạn 2A vận hành thử', 'Gemalink Phase 2A begins trial operations', 'Gemalink bắt đầu chạy thử bến Phase 2A, nâng công suất từ 1.5M lên 2.0M TEU/năm.', 'Gemadept IR', 'competitor', 'positive', '[]', '["P006"]', '["CM-TV"]'),
('N014', '2025-04-15', 'Nam Đình Vũ GĐ3 khánh thành', 'Nam Dinh Vu Phase 3 inaugurated', 'Cụm Nam Đình Vũ khánh thành GĐ3 — công suất cảng cộng dồn đạt 2M TEU/năm, lớn nhất miền Bắc về cảng sông.', 'Gemadept IR', 'competitor', 'positive', '[]', '["P001", "P007"]', '["Hải Phòng"]'),
('N015', '2025-05-20', 'CMA CGM mở dịch vụ NEMO kết nối Việt Nam-Nam Á-Úc', 'CMA CGM launches NEMO service Vietnam-South Asia-Australia', 'CMA CGM công bố tuyến NEMO mới, ghé Gemalink 1 lần/tuần, phục vụ hàng xuất Úc và Nam Á.', 'Phaata', 'route', 'positive', '["L03"]', '["P006"]', '["CM-TV"]'),
('N016', '2025-06-10', 'Wan Hai mở tuyến AX1 ghé Cái Mép', 'Wan Hai launches AX1 calling Cai Mep', 'Wan Hai Lines mở tuyến AX1 mới, tăng tần suất ghé CM-TV từ 3 lên 5 chuyến/tháng, dùng cả TCIT và Gemalink.', 'Linerlytica', 'route', 'positive', '["L11"]', '["P010", "P006"]', '["CM-TV"]'),
('N017', '2025-07-03', 'Mỹ công bố thuế mới với hàng xuất khẩu Việt Nam', 'US announces new tariffs on Vietnamese imports', 'Chính phủ Mỹ công bố điều chỉnh thuế quan đối với một số mặt hàng Việt Nam. Các doanh nghiệp dệt may, điện tử lo ngại ảnh hưởng.', 'Vietstock', 'tariff', 'negative', '[]', '[]', '["US-VN"]'),
('N018', '2025-07-22', 'ZIM tăng cường hiện diện tại Cát Mép với 6 call/tháng', 'ZIM ramps CM-TV presence to 6 calls/month', 'Sau thoả thuận slot với MSC, ZIM đẩy mạnh ghé TCIT và CMIT, 6 chuyến/tháng. Chưa có kế hoạch ghé Gemalink.', 'Phaata', 'competitor', 'neutral', '["L10"]', '["P010", "P013"]', '["CM-TV"]'),
('N019', '2025-08-15', 'HMM tăng tuyến Asia-Europe qua CM-TV', 'HMM increases Asia-Europe via CM-TV', 'HMM công bố tăng 2 tuyến Asia-Europe mới qua TCIT, mục tiêu tăng sản lượng VN 30% năm 2025.', 'Phaata', 'route', 'positive', '["L08"]', '["P010", "P006"]', '["CM-TV"]'),
('N020', '2025-09-02', 'Bão số 3 đổ bộ miền Trung — Dung Quất đóng 36h', 'Typhoon #3 hits Central VN — Dung Quat closed 36h', 'Bão số 3 gây ảnh hưởng cảng Dung Quất và Quy Nhơn. Dung Quất tạm đóng cửa 36 giờ, hoạt động trở lại bình thường 5/9.', 'CafeF', 'weather', 'negative', '[]', '["P003"]', '["Miền Trung"]'),
('N021', '2025-10-01', 'Gemadept công bố Q3/2025 doanh thu tăng 28% YoY', 'Gemadept Q3 2025 revenue +28% YoY', 'Doanh thu Q3/2025 đạt 1,580 tỷ đồng, tăng 28% YoY nhờ Gemalink full công suất.', 'Vietstock', 'competitor', 'positive', '[]', '["P006"]', '["CM-TV"]'),
('N022', '2025-10-15', 'Nam Đình Vũ GĐ3 vận hành thương mại đầy đủ', 'Nam Dinh Vu Phase 3 fully operational', 'GĐ3 Nam Đình Vũ bàn giao cần trục STS và RTG, bắt đầu vận hành thương mại 10/2025 sau thử nghiệm 6 tháng.', 'Gemadept IR', 'competitor', 'positive', '[]', '["P001", "P007"]', '["Hải Phòng"]'),
('N023', '2025-11-20', 'Maersk giảm call tại Gemalink — chuyển hub về TCIT theo mô hình Gemini', 'Maersk reduces Gemalink calls — shifts hub to TCIT under Gemini model', 'Dữ liệu cảng vụ cho thấy Maersk đã giảm port call tại Gemalink 25% so với Q1/2025, đồng thời tăng tương ứng tại TCIT. Đây là bước đi phù hợp mô hình Gemini hub-and-spoke.', 'Phaata', 'competitor', 'negative', '["L02"]', '["P006", "P010"]', '["CM-TV"]'),
('N024', '2025-12-05', 'OOCL mở thêm tuyến Asia-Europe qua Gemalink', 'OOCL adds Asia-Europe service via Gemalink', 'OOCL (Ocean Alliance) mở tuyến FE4 mới, ghé Gemalink hàng tuần, mức tăng 1 call/tuần cho Gemalink.', 'Phaata', 'route', 'positive', '["L16"]', '["P006"]', '["CM-TV"]'),
('N025', '2025-12-20', 'TCIT hoàn thành mở rộng bến C4, đón tàu 200k DWT', 'TCIT completes berth C4 expansion — 200k DWT ready', 'TCIT hoàn thành bến C4 dài 400m, chính thức đón tàu mega 200k DWT. Cạnh tranh trực tiếp với Gemalink.', 'Phaata', 'competitor', 'negative', '[]', '["P010", "P006"]', '["CM-TV"]'),
('N026', '2026-01-08', 'Gemini vận hành ổn định — Maersk tiếp tục giảm Gemalink', 'Gemini stabilizes — Maersk further reduces Gemalink', 'Sau 1 năm vận hành Gemini Cooperation, Maersk chính thức rút 3 tuyến ra khỏi Gemalink, chuyển toàn bộ về TCIT. Sản lượng Maersk tại Gemalink giảm mạnh từ Q1/2026.', 'Lloyd List', 'competitor', 'negative', '["L02"]', '["P006", "P010"]', '["CM-TV"]'),
('N027', '2026-01-20', 'ZIM-MSC mở tuyến ZX2 TransPacific qua CMIT', 'ZIM-MSC launches ZX2 TransPacific via CMIT', 'Liên minh slot ZIM-MSC chính thức vận hành tuyến ZX2 qua CMIT, 1 chuyến/tuần sang Los Angeles. Gemalink không có trong rotation.', 'Linerlytica', 'route', 'positive', '["L01", "L10"]', '["P013"]', '["CM-TV"]'),
('N028', '2026-02-01', 'Khung giá sàn bốc xếp cảng nước sâu tăng 10%', 'Deepsea stevedoring price floor raised 10%', 'Quyết định 810/QĐ-BGTVT sửa đổi có hiệu lực 1/2/2026 — tăng 10% giá sàn cho cảng nước sâu (Gemalink, CMIT, SSIT, HICT, TC-HICT). Cảng sông không thay đổi.', 'Cổng thông tin Bộ XD', 'regulation', 'positive', '[]', '["P006", "P013", "P014", "P015", "P021", "P022"]', '["VN"]'),
('N029', '2026-02-15', 'Hapag-Lloyd tăng call Gemalink theo Gemini', 'Hapag-Lloyd increases Gemalink calls under Gemini', 'Dù Maersk giảm, Hapag-Lloyd lại tăng call Gemalink lên 6/tháng — cân bằng phần nào mất mát từ Maersk. Gemadept đang tích cực tiếp cận Hapag.', 'Phaata', 'competitor', 'positive', '["L05"]', '["P006"]', '["CM-TV"]'),
('N030', '2026-03-02', 'Mỹ đe doạ thuế 25% hàng Việt Nam từ Q2/2026', 'US threatens 25% tariff on VN goods from Q2 2026', 'Chính quyền Mỹ công bố sẽ áp thuế bổ sung 25% lên một số mặt hàng Việt Nam từ Q2/2026 nếu không đạt được thoả thuận thương mại. Hàng điện tử, dệt may, gỗ đứng trước rủi ro.', 'Vietstock', 'tariff', 'negative', '[]', '[]', '["US-VN"]'),
('N031', '2018-07-06', 'Trump áp thuế 25% lên 34 tỷ USD hàng Trung Quốc — bắt đầu thương chiến', 'Trump imposes 25% tariff on $34B Chinese goods — trade war starts', 'Chính quyền Trump áp thuế 25% lên 34 tỷ USD hàng Trung Quốc, mở đầu thương chiến Mỹ-Trung. Dòng hàng dịch chuyển sang VN bắt đầu từ đây.', 'Reuters', 'tariff', 'neutral', '[]', '[]', '["US-China"]'),
('N032', '2019-05-10', 'Trump tăng thuế lên 25% với 200 tỷ USD hàng Trung Quốc', 'Trump raises tariff to 25% on $200B Chinese goods', 'Leo thang thương chiến, thuế tăng lên 25% với 200 tỷ USD hàng TQ — VN hưởng lợi dòng hàng dịch chuyển.', 'Reuters', 'tariff', 'positive', '[]', '[]', '["US-China"]'),
('N033', '2024-12-08', 'Sương mù dày đặc Hải Phòng — nhiều tàu chờ luồng', 'Dense fog in Hai Phong — vessels wait channel', 'Sương mù giảm tầm nhìn tại luồng Lạch Huyện, nhiều tàu chờ cập bến. Nam Đình Vũ ảnh hưởng nhẹ.', 'CafeF', 'weather', 'negative', '[]', '["P001", "P020", "P021"]', '["Hải Phòng"]'),
('N034', '2025-01-28', 'Sương mù Hải Phòng — chậm trễ 1-2 ngày', 'Hai Phong fog — 1-2 day delays', 'Đợt sương mù thứ 2 mùa đông gây chậm cập tàu tại Hải Phòng 1-2 ngày. Không ảnh hưởng đáng kể sản lượng.', 'CafeF', 'weather', 'negative', '[]', '["P001", "P007", "P020", "P021", "P025"]', '["Hải Phòng"]'),
('N035', '2026-02-10', 'Sương mù mùa đông Hải Phòng nặng — ảnh hưởng lịch tàu', 'Dense winter fog in Hai Phong affects vessel schedules', 'Sương mù dày đặc miền Bắc giai đoạn trước Tết gây chậm cập tàu đồng loạt các cảng Hải Phòng 2-3 ngày.', 'CafeF', 'weather', 'negative', '[]', '["P001", "P007", "P020", "P021"]', '["Hải Phòng"]'),
('N036', '2025-05-02', 'Alphaliner: Gemini có thể tái cấu trúc năm 2', 'Alphaliner: Gemini may restructure year 2', 'Alphaliner dự báo Gemini Cooperation có thể cần tái cấu trúc năm thứ 2 nếu các tuyến Asia-Europe không đạt target reliability 90%.', 'Alphaliner', 'alliance', 'neutral', '["L02", "L05"]', '[]', '["global"]'),
('N037', '2025-08-28', 'COSCO mở rộng tuyến Ấn Độ qua Gemalink', 'COSCO expands India routes via Gemalink', 'COSCO mở rộng tuyến IMX Asia-Ấn Độ, tăng tần suất ghé Gemalink lên 2 chuyến/tuần.', 'Phaata', 'route', 'positive', '["L04"]', '["P006"]', '["CM-TV"]'),
('N038', '2025-09-20', 'Evergreen đầu tư terminal mới tại CM-TV', 'Evergreen invests new CM-TV terminal', 'Evergreen công bố ký kết đầu tư vào dự án cảng mới khu vực Cái Mép, công suất 2M TEU/năm, dự kiến 2028.', 'Vietstock', 'competitor', 'neutral', '["L07"]', '[]', '["CM-TV"]'),
('N039', '2024-04-25', 'SITC mở rộng đội tàu 24 chiếc mới', 'SITC expands fleet with 24 new vessels', 'SITC công bố đầu tư 24 tàu feeder 1,800 TEU mới, ưu tiên tuyến Việt Nam - Hàn - Nhật - TQ.', 'Linerlytica', 'competitor', 'positive', '["L12"]', '[]', '["Intra-Asia"]'),
('N040', '2024-07-08', 'Phí cảng biển TP.HCM đề xuất tăng', 'HCMC port fees proposed to rise', 'UBND TP.HCM đề xuất tăng phí hạ tầng cảng biển 30% từ 2025, áp dụng cho Cát Lái và các ICD.', 'CafeF', 'regulation', 'negative', '[]', '["P030", "P031", "P032", "P004"]', '["HCM"]'),
('N041', '2024-10-18', 'CMA CGM và Gemadept gia hạn thoả thuận liên doanh Gemalink', 'CMA CGM and Gemadept extend Gemalink JV', 'CMA Terminals (CMA CGM) và Gemadept chính thức gia hạn hợp tác liên doanh Gemalink thêm 25 năm, cam kết tăng vốn cho GĐ2.', 'Gemadept IR', 'route', 'positive', '["L03"]', '["P006"]', '["CM-TV"]'),
('N042', '2025-06-25', 'Hapag-Lloyd cân nhắc làm thêm call Gemalink', 'Hapag-Lloyd considers additional Gemalink call', 'Briefing Q2: Hapag-Lloyd cân nhắc bổ sung 1 call/tuần tại Gemalink trong khuôn khổ Gemini để bù đắp giảm call do hub chính chuyển sang TCIT.', 'Phaata', 'route', 'positive', '["L05"]', '["P006"]', '["CM-TV"]'),
('N043', '2025-11-04', 'TCIT vượt Gemalink về số call hãng lớn Q3/2025', 'TCIT surpasses Gemalink in major line calls Q3 2025', 'Theo dữ liệu cảng vụ Vũng Tàu, TCIT đón nhiều port call của top-10 hãng tàu hơn Gemalink lần đầu tiên Q3/2025.', 'Phaata', 'competitor', 'negative', '[]', '["P006", "P010"]', '["CM-TV"]'),
('N044', '2024-08-22', 'Cát Lái đạt kỷ lục 5.8M TEU năm 2024 (ước tính)', 'Cat Lai estimated 5.8M TEU record 2024', 'Cát Lái (Tân Cảng SG) ước thông qua 5.8M TEU năm 2024, tiếp tục là cảng container lớn nhất VN.', 'Vietstock', 'competitor', 'neutral', '[]', '["P030"]', '["HCM"]'),
('N045', '2024-09-28', 'MSC tìm đối tác cảng VN sau tan rã 2M', 'MSC seeks VN port partner post-2M', 'MSC phát tín hiệu tìm đối tác cảng chiến lược tại VN để chuẩn bị standalone 2/2025. Gemalink, CMIT, SSIT đều trong radar.', 'Alphaliner', 'alliance', 'neutral', '["L01"]', '["P006", "P013", "P014"]', '["CM-TV"]'),
('N046', '2025-03-20', 'MSC tăng 3 call/tháng tại Gemalink', 'MSC adds 3 calls/month at Gemalink', 'MSC chính thức tăng tần suất call Gemalink từ 3 lên 6/tháng bắt đầu 3/2025, trong chiến lược standalone.', 'Phaata', 'route', 'positive', '["L01"]', '["P006"]', '["CM-TV"]'),
('N047', '2024-05-30', 'Hãng tàu cân nhắc hub lại tại CM-TV', 'Lines re-considering CM-TV hub strategy', 'Linerlytica: Nhiều hãng tàu đang đánh giá lại chiến lược hub tại CM-TV trước thềm tái cấu trúc liên minh 2/2025.', 'Linerlytica', 'alliance', 'neutral', '[]', '["P006", "P010", "P013", "P014"]', '["CM-TV"]'),
('N048', '2025-04-05', 'Gemadept đặt target 2026 thị phần 18%', 'Gemadept targets 18% market share 2026', 'Trong AGM, Chủ tịch Gemadept đặt target thị phần container 18% năm 2026, chủ yếu nhờ Gemalink GĐ2A và NDV GĐ3.', 'Gemadept IR', 'competitor', 'positive', '[]', '[]', '["VN"]'),
('N049', '2026-03-15', 'Gemini Cooperation có thể rút thêm tuyến CM-TV', 'Gemini may pull more CM-TV routes', 'Briefing Lloyd List: Gemini Cooperation đánh giá hiệu quả năm 1, có thể rút thêm 1-2 tuyến CM-TV trong Q2/2026 để tối ưu hub-spoke.', 'Lloyd List', 'alliance', 'negative', '["L02", "L05"]', '["P006", "P010"]', '["CM-TV"]'),
('N050', '2024-06-30', 'ZIM công bố liên minh xuyên Thái Bình Dương mới', 'ZIM announces new TransPacific alliance', 'ZIM có kế hoạch mở rộng tuyến TransPacific thông qua liên minh slot mới với MSC, bắt đầu 2/2025. VN là điểm trọng tâm.', 'Alphaliner', 'alliance', 'neutral', '["L01", "L10"]', '[]', '["global"]'),
('N051', '2025-07-18', 'Chiến tranh Trung Đông — tuyến Biển Đỏ tiếp tục tránh Suez', 'Middle East conflict — Red Sea diversions continue', 'Các hãng tiếp tục vòng qua Mũi Hảo Vọng, thời gian Asia-Europe kéo dài 14 ngày. Tăng nhu cầu công suất.', 'Lloyd List', 'route', 'neutral', '[]', '[]', '["global"]'),
('N052', '2024-11-28', 'HICT Lạch Huyện tăng thị phần Hải Phòng', 'HICT Lach Huyen gains Hai Phong market share', 'HICT (Lạch Huyện Hateco-Itochu) tăng thị phần cont Hải Phòng từ 25% lên 32% trong 9T/2024 nhờ đón tàu mẹ Asia-US West Coast.', 'Phaata', 'competitor', 'negative', '[]', '["P021", "P001"]', '["Hải Phòng"]'),
('N053', '2025-04-22', 'Cảng VN qua mốc 16 triệu TEU 6T/2025 — tăng 13% YoY', 'VN ports cross 16M TEU H1 2025 — +13% YoY', 'Tổng sản lượng container qua các cảng VN đạt 16.3M TEU trong 6T/2025, tăng 13% YoY, dẫn dắt bởi cụm CM-TV và Hải Phòng.', 'Vietstock', 'competitor', 'positive', '[]', '[]', '["VN"]'),
('N054', '2025-12-12', 'CMIT mở rộng thêm 2 tuyến TransPacific cho ZIM-MSC', 'CMIT adds 2 more TransPacific routes for ZIM-MSC', 'CMIT công bố ký bổ sung 2 tuyến TransPacific tuần cho liên minh ZIM-MSC từ 1/2026 — củng cố vị thế hub xuyên TBD.', 'Phaata', 'competitor', 'negative', '["L01", "L10"]', '["P013"]', '["CM-TV"]'),
('N055', '2024-04-15', 'Khối lượng XK Mỹ năm 2024 dự báo +8%', 'US export volume forecast +8% for 2024', 'Linerlytica dự báo khối lượng XK VN-Mỹ tăng 8% năm 2024 — TransPacific tiếp tục là tuyến tăng trưởng nhanh nhất.', 'Linerlytica', 'route', 'positive', '[]', '[]', '["US-VN"]'),
('N056', '2025-10-25', 'Premier Alliance đánh giá hub VN tại CM-TV', 'Premier Alliance evaluates VN hub at CM-TV', 'Briefing nội bộ ONE: Premier Alliance đánh giá lập hub VN, ưu tiên TCIT và CMIT, có thể giảm Gemalink trừ khi giá ưu đãi.', 'Linerlytica', 'alliance', 'negative', '["L06", "L08", "L09"]', '["P006", "P010", "P013"]', '["CM-TV"]'),
('N057', '2026-03-25', 'Hapag-Lloyd ký thoả thuận khung dài hạn với Gemalink', 'Hapag-Lloyd signs long-term framework with Gemalink', 'Trong khuôn khổ Gemini, Hapag-Lloyd ký framework deal 3 năm với Gemalink, cam kết tối thiểu 5 call/tháng, ưu đãi giá xếp dỡ.', 'Phaata', 'route', 'positive', '["L05"]', '["P006"]', '["CM-TV"]'),
('N058', '2025-08-05', 'Bộ XD: Khung giá sàn cảng nước sâu được duyệt', 'MOC: Deepsea price floor approved', 'Bộ Xây dựng chính thức ban hành Quyết định sửa đổi 810/QĐ-BGTVT — tăng 10% giá sàn cảng nước sâu hiệu lực 1/2/2026.', 'Cổng thông tin Bộ XD', 'regulation', 'positive', '[]', '["P006", "P013", "P014", "P015", "P021", "P022"]', '["VN"]'),
('N059', '2024-04-10', 'Maersk báo Q1/2024 lợi nhuận giảm', 'Maersk Q1 2024 profit down', 'Maersk báo Q1/2024 lợi nhuận giảm sâu do giá cước phục hồi chậm, dự báo phải tái cấu trúc network tiếp theo.', 'Lloyd List', 'competitor', 'negative', '["L02"]', '[]', '["global"]');
